const WelcomeScreen: React.FC = () => {
  const router = useRouter();
  const BACKEND_URL = process.env.EXPO_PUBLIC_BACKEND_URL ?? "";
  const API_BASE = `${BACKEND_URL}api`;

  const [fontsLoaded] = useFonts({
    "Poppins-Bold": require("@/assets/fonts/Poppins-Bold.ttf"),
    CalligraphyBrilliant: require("@/assets/fonts/CalligraphyBrilliant.otf"),
  });

  const topAnim = useRef(new Animated.Value(0)).current;
  const taglineAnim = useRef(new Animated.Value(0)).current;
  const btnsAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    const init = async () => {
      const token = await AsyncStorage.getItem("token");

      console.log(process.env.EXPO_PUBLIC_BACKEND_URL);

      if (token) {
  try {
    console.log("Saved token exists:", token);

    const res = await fetch(`${API_BASE}/auth/verify-token`, {
      method: "GET",
      headers: {
        Authorization: `Bearer ${token}`,
      },
    });

    const text = await res.text();
    console.log("verify-token status:", res.status);
    console.log("verify-token response:", text);

    if (res.ok) {
      router.replace("/(tabs)");
      return;
    } else {
      await AsyncStorage.removeItem("token");
      console.log("Token removed because verify-token was not ok");
    }
  } catch (error) {
    console.log("verify-token fetch error:", error);
  }
}

      // run animations if not redirected
      Animated.stagger(150, [
        Animated.spring(topAnim, {
          toValue: 1,
          useNativeDriver: true,
          tension: 55,
          friction: 9,
        }),
        Animated.spring(taglineAnim, {
          toValue: 1,
          useNativeDriver: true,
          tension: 55,
          friction: 9,
        }),
        Animated.spring(btnsAnim, {
          toValue: 1,
          useNativeDriver: true,
          tension: 55,
          friction: 9,
        }),
      ]).start();
    };

    init();
  }, []);

  const fadeUp = (anim: Animated.Value, offset = 36) => ({
    opacity: anim,
    transform: [
      {
        translateY: anim.interpolate({
          inputRange: [0, 1],
          outputRange: [offset, 0],
        }),
      },
    ],
  });

  const poppins = fontsLoaded ? "Poppins-Bold" : undefined;
  const calligraphy = fontsLoaded ? "CalligraphyBrilliant" : undefined;

  return (
    <SafeAreaView style={styles.safeArea} edges={["top", "bottom"]}>
      <StatusBar barStyle="light-content" backgroundColor="#0a0a0a" />

      {/* Subtle purple glow */}
      <View style={styles.glowBlob} pointerEvents="none" />

      {/* ── TOP: Logo + brand name ── */}
      <Animated.View style={[styles.topSection, fadeUp(topAnim, 24)]}>
        <Text style={[styles.brandName, { fontFamily: poppins }]}>Soothe</Text>
        <SvgXml xml={logoXml} width={102} height={98} />
      </Animated.View>

      {/* ── MIDDLE: spacer ── */}
      <View style={styles.spacer} />

      {/* ── BOTTOM CONTENT: welcome + tagline + buttons ── */}
      <View style={styles.bottomContent}>
        {/* Welcome label */}
        <Animated.View style={fadeUp(taglineAnim, 20)}>
          <Text style={styles.welcomeLabel}>Welcome</Text>
        </Animated.View>

        {/* Title SVG */}
        <Animated.View style={[styles.titleSvg, fadeUp(taglineAnim, 28)]}>
          <SvgXml
            xml={titleXml}
            width="100%"
            height={undefined}
            style={{ aspectRatio: 938 / 314 }}
          />
        </Animated.View>

        {/* Buttons */}
        <Animated.View style={[styles.buttons, fadeUp(btnsAnim, 24)]}>
          <TouchableOpacity
            style={styles.signUpBtn}
            activeOpacity={0.85}
            onPress={() => router.push("/signup")}
          >
            <LinearGradient
              colors={["#b94fff", "#a339ff"]}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 1 }}
              style={styles.signUpGradient}
            >
              <Text style={[styles.signUpText, { fontFamily: poppins }]}>
                Create Account
              </Text>
            </LinearGradient>
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.loginBtn}
            activeOpacity={0.75}
            onPress={() => router.push("/login")}
          >
            <Text style={styles.loginText}>
              Already have an account?{" "}
              <Text style={styles.loginAccent}>Log in</Text>
            </Text>
          </TouchableOpacity>
        </Animated.View>
      </View>
    </SafeAreaView>
  );
};

